import secrets
from cryptography.fernet import Fernet
import base64
import os

def generate_key():
    key = secrets.token_bytes(32)
    return base64.urlsafe_b64encode(key)

def encrypt_data(data, key):
    cipher_suite = Fernet(key)
    encrypted_data = cipher_suite.encrypt(data.encode())
    return encrypted_data.decode()

def store_encrypted_data(data):
    # Generate a new encryption key
    key = generate_key()
    
    # Encrypt the data using the generated key
    encrypted_data = encrypt_data(data, key)
    
    # Store the encrypted data and the key securely (e.g., in environment variables or secure storage)
    os.environ['ENCRYPTED_DATA'] = encrypted_data
    os.environ['KEY'] = key.decode()

def retrieve_encrypted_data():
    encrypted_data = os.environ.get('ENCRYPTED_DATA')
    key = base64.urlsafe_b64decode(os.environ.get('KEY'))
    
    # Decrypt the data using the stored key
    cipher_suite = Fernet(key)
    decrypted_data = cipher_suite.decrypt(encrypted_data.encode())
    
    return decrypted_data.decode()